@charset "UTF-8";
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap");
/*======================================
Variables globales
======================================*/
:root {
  --font-primary: "Poppins", sans-serif;
  /* Couleurs Typographie */
  --color-text-dark: #39444D;
  --color-text-gray: #6B7280;
  --color-text-light: #9CA3AF;
  /* Couleurs Pilules & UI */
  --color-bg: #ffffff;
  --color-bg-gray-light: #F9FAFB;
  --color-border: #E5E7EB;
  --color-pill-true-bg: #ECFDF5;
  --color-pill-true-text: #007A56;
  --color-pill-false-bg: #F3F4F6;
  --color-pill-false-text: #9CA3AF;
  --color-primary: #82DB34;
  --color-primary-hover: #75C62F;
  --radius-main: 12px;
  --radius-sm: 8px;
  --radius-pill: 20px;
  --spacing: 1.5rem;
  --spacing-half: 0.75rem;
  --shadow-card: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
}

/*======================================
Conteneur général
======================================*/
.app {
  font-family: var(--font-primary);
  background: var(--color-bg);
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: var(--spacing-half);
  box-sizing: border-box;
}

/*======================================
Barre de Contrôle (Filtres & Tri)
======================================*/
.top-bar {
  width: 100%;
  max-width: 1000px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  margin-bottom: var(--spacing);
  padding: 0 4px;
  box-sizing: border-box;
}

.top-bar-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  width: 100%;
  gap: 24px;
  flex-wrap: wrap;
}

/* --- Dropdown Filtres --- */
.filter-container {
  position: relative;
  display: flex;
  align-items: center;
  gap: 12px;
}

.filter-label {
  color: var(--color-text-gray);
  font-size: 0.9rem;
  font-weight: 500;
}

.dropdown-button {
  padding: 8px 16px;
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  cursor: pointer;
  font-family: var(--font-primary);
  font-weight: 600;
  font-size: 0.9rem;
  color: var(--color-text-dark);
  display: flex;
  align-items: center;
  gap: 8px;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
  min-width: 180px;
  justify-content: space-between;
  transition: all 0.2s;
}

.dropdown-button:hover, .dropdown-button.is-open {
  border-color: var(--color-primary);
}

/* Badges de compteur sur le bouton */
.filter-badge {
  background: var(--color-primary);
  color: white;
  font-size: 0.75rem;
  padding: 2px 6px;
  border-radius: 10px;
  margin-left: 4px;
}

/* L'overlay transparent pour refermer au clic extérieur */
.dropdown-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 90;
}

.dropdown-menu {
  position: absolute;
  top: calc(100% + 8px);
  left: 0;
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.1);
  z-index: 100;
  min-width: 260px;
  max-height: 300px;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  padding: 8px 0;
}

.filter-option {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 16px;
  cursor: pointer;
  transition: background 0.2s;
  font-size: 0.9rem;
  color: var(--color-text-dark);
  user-select: none;
}

.filter-option:hover {
  background-color: var(--color-bg-gray-light);
}

.filter-option input[type=checkbox] {
  accent-color: var(--color-primary);
  width: 16px;
  height: 16px;
  cursor: pointer;
}

/* --- Dropdown Tri --- */
.sort-container {
  display: flex;
  align-items: center;
  gap: 12px;
}

.sort-label {
  color: var(--color-text-gray);
  font-size: 0.9rem;
  font-weight: 500;
}

.sort-select {
  padding: 8px 32px 8px 16px;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  appearance: none;
  background-color: var(--color-bg);
  cursor: pointer;
  color: var(--color-text-dark);
  font-weight: 600;
  font-size: 0.9rem;
  font-family: var(--font-primary);
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
  transition: all 0.2s ease;
  background-image: url("data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%236B7280%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22%2F%3E%3C%2Fsvg%3E");
  background-repeat: no-repeat;
  background-position: right 12px top 50%;
  background-size: 10px auto;
}

.sort-select:hover {
  border-color: #B8BFD1;
}

.sort-select:focus {
  outline: none;
  border-color: var(--color-primary);
}

/* Compteur de résultats */
.results-count {
  font-size: 0.85rem;
  color: var(--color-text-gray);
  font-weight: 500;
}

/*======================================
Carte d'offre (Desktop)
======================================*/
.offer-card {
  width: 100%;
  max-width: 1000px;
  margin: var(--spacing-half) 0;
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-main);
  box-shadow: var(--shadow-card);
  display: flex;
  flex-direction: row;
  align-items: stretch;
  overflow: hidden;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.offer-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.05);
}

.col-insurer {
  display: flex;
  flex-direction: column;
  padding: var(--spacing);
  flex: 0 0 25%;
  box-sizing: border-box;
}

.logo-box {
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  padding: 12px;
  display: flex;
  justify-content: center;
  align-items: center;
  margin-bottom: var(--spacing-half);
  height: 60px;
}

.offer-image {
  max-width: 100%;
  max-height: 100%;
  object-fit: contain;
}

.insurer-name {
  color: var(--color-text-dark);
  font-size: 1.1rem;
  font-weight: 700;
  line-height: 1.2;
}

.formula-name {
  color: var(--color-text-light);
  font-size: 0.9rem;
  font-weight: 400;
  margin-top: 2px;
}

.col-features {
  flex: 1;
  padding: var(--spacing);
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: var(--spacing-half);
}

.franchise-row {
  display: flex;
  align-items: center;
  gap: var(--spacing-half);
  margin-bottom: 4px;
}

.franchise-label {
  color: var(--color-text-light);
  font-size: 0.8rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.franchise-value-pill {
  background: var(--color-bg-gray-light);
  color: var(--color-text-dark);
  font-weight: 700;
  font-size: 0.9rem;
  padding: 4px 12px;
  border-radius: var(--radius-pill);
}

.pills-container {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.feature-pill {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  border-radius: var(--radius-pill);
  font-size: 0.85rem;
  font-weight: 500;
}

.feature-pill.true {
  background-color: var(--color-pill-true-bg);
  color: var(--color-pill-true-text);
}

.feature-pill.false {
  background-color: var(--color-pill-false-bg);
  color: var(--color-pill-false-text);
}

.feature-pill.false span {
  text-decoration: line-through;
}

.vertical-divider {
  width: 1px;
  background-color: var(--color-border);
  margin: var(--spacing) 0;
}

.col-action {
  padding: var(--spacing);
  flex: 0 0 25%;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  gap: 12px;
}

.price-box {
  display: flex;
  align-items: baseline;
  justify-content: center;
  gap: 2px;
}

.price-value {
  color: var(--color-text-dark);
  font-size: 2.2rem;
  font-weight: 600;
  letter-spacing: -0.02em;
}

.price-unit {
  color: var(--color-text-light);
  font-size: 0.9rem;
  font-weight: 500;
}

.savings-pill {
  padding: 4px 12px;
  border-radius: var(--radius-pill);
  font-size: 0.85rem;
  font-weight: 500;
}

.btn-select {
  background: var(--color-primary);
  color: #fff;
  padding: 10px 24px;
  border-radius: var(--radius-pill);
  border: none;
  cursor: pointer;
  font-weight: 600;
  font-size: 1rem;
  font-family: var(--font-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  transition: background-color 0.2s ease;
  width: 100%;
  position: relative;
  overflow: hidden;
}

.btn-select:hover {
  background: var(--color-primary-hover);
}

.btn-select::after {
  content: "";
  position: absolute;
  top: 0;
  left: -100%;
  width: 50%;
  height: 100%;
  background: linear-gradient(to right, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.4) 50%, rgba(255, 255, 255, 0) 100%);
  transform: skewX(-20deg);
  transition: left 0.6s ease-in-out;
}

.btn-select:hover::after {
  left: 150%;
}

/*======================================
Responsive (Mobile & Tablette)
======================================*/
@media (max-width: 768px) {
  .top-bar-header {
    flex-direction: column;
    align-items: flex-start;
  }
  .offer-card {
    flex-direction: column;
    border-left-width: 4px !important;
  }
  .col-insurer, .col-action {
    flex: none;
    width: 100%;
  }
  .col-insurer {
    padding-bottom: 0;
    flex-direction: row;
    align-items: center;
    gap: var(--spacing);
  }
  .logo-box {
    margin-bottom: 0;
    width: 80px;
    height: 50px;
  }
  .col-features {
    padding: var(--spacing);
  }
  .vertical-divider {
    display: none;
  }
  .col-action {
    padding-top: 0;
    align-items: stretch;
    border-top: 1px solid var(--color-border);
    padding-top: var(--spacing);
  }
  .price-box, .savings-pill {
    align-self: center;
  }
}

