function formatNumber(num) {
  return Number.isInteger(num) ? num.toString() : num.toFixed(2).replace('.', ',');
}

// Récupère l'objet complet de l'option
function getFeatureByName(features, features_label) {
  if (!features || !features.options) return {};
  for (let category of features.options) {
    if (!category.options) continue;
    for (let option of category.options) {
      if (option.label === features_label) {
        return option;
      }
    }
  }
  return {};
}

// Récupère uniquement la valeur formatée (utilisé pour la première option)
