	justify-content: space-between;
	align-items: center;
	width: 100%;
	gap: 24px;
	flex-wrap: wrap;
}

/* --- Dropdown Filtres --- */
.filter-container {
	position: relative;
	display: flex;
	align-items: center;
	gap: 12px;
}

.filter-label {
	color: var(--color-text-gray);
	font-size: 0.9rem;
	font-weight: 500;
}

.dropdown-button {
	padding: 8px 16px;
	background: var(--color-bg);
	border: 1px solid var(--color-border);
	border-radius: var(--radius-sm);
	cursor: pointer;
	font-family: var(--font-primary);
	font-weight: 600;
	font-size: 0.9rem;
	color: var(--color-text-dark);
	display: flex;
	align-items: center;
	gap: 8px;
	box-shadow: 0 1px 2px rgba(0,0,0,0.05);
	min-width: 180px;
