	font-size: 0.75rem;
	padding: 2px 6px;
	border-radius: 10px;
	margin-left: 4px;
}

/* L'overlay transparent pour refermer au clic extérieur */
.dropdown-overlay {
	position: fixed;
	top: 0; left: 0; right: 0; bottom: 0;
	z-index: 90;
}

.dropdown-menu {
	position: absolute;
	top: calc(100% + 8px);
	left: 0;
	background: var(--color-bg);
