======================================*/
.offer-card {
	width: 100%;
	max-width: 1000px;
	margin: var(--spacing-half) 0;
	background: var(--color-bg);
	border: 1px solid var(--color-border);
	border-radius: var(--radius-main);
	box-shadow: var(--shadow-card);
	display: flex;
	flex-direction: row;
	align-items: stretch;
	overflow: hidden;
	transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.offer-card:hover {
	transform: translateY(-2px);
	box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.05);
}

.col-insurer {
	display: flex;
	flex-direction: column;
	padding: var(--spacing);
	flex: 0 0 25%;
	box-sizing: border-box;
}

.logo-box {
	border: 1px solid var(--color-border);
	border-radius: var(--radius-sm);
	padding: 12px;
	display: flex;
	justify-content: center;
	align-items: center;
	margin-bottom: var(--spacing-half);
	height: 60px;
}

.offer-image { max-width: 100%; max-height: 100%; object-fit: contain; }

.insurer-name {
	color: var(--color-text-dark);
	font-size: 1.1rem;
	font-weight: 700;
	line-height: 1.2;
}

.formula-name {
	color: var(--color-text-light);
	font-size: 0.9rem;
	font-weight: 400;
	margin-top: 2px;
}

.col-features {
	flex: 1;
	padding: var(--spacing); 
	display: flex;
	flex-direction: column;
	justify-content: center;
	gap: var(--spacing-half);
}

.franchise-row {
	display: flex;
	align-items: center;
	gap: var(--spacing-half);
	margin-bottom: 4px;
}

.franchise-label {
	color: var(--color-text-light);
	font-size: 0.8rem;
	font-weight: 600;
	letter-spacing: 0.05em;
	text-transform: uppercase;
}

.franchise-value-pill {
	background: var(--color-bg-gray-light);
	color: var(--color-text-dark);
	font-weight: 700;
	font-size: 0.9rem;
	padding: 4px 12px;
	border-radius: var(--radius-pill);
}

.pills-container { display: flex; flex-wrap: wrap; gap: 8px; }

.feature-pill {
	display: inline-flex;
	align-items: center;
	gap: 6px;
	padding: 6px 12px;
	border-radius: var(--radius-pill);
	font-size: 0.85rem;
	font-weight: 500;
}

.feature-pill.true { background-color: var(--color-pill-true-bg); color: var(--color-pill-true-text); }
.feature-pill.false { background-color: var(--color-pill-false-bg); color: var(--color-pill-false-text); }
.feature-pill.false span { text-decoration: line-through; }

.vertical-divider {
	width: 1px;
	background-color: var(--color-border);
	margin: var(--spacing) 0;
}

.col-action {
	padding: var(--spacing);
	flex: 0 0 25%;
	box-sizing: border-box;
	display: flex;
	flex-direction: column;
	align-items: center;
	justify-content: center;
	text-align: center;
	gap: 12px;
}

.price-box { display: flex; align-items: baseline; justify-content: center; gap: 2px; }
.price-value { color: var(--color-text-dark); font-size: 2.2rem; font-weight: 600; letter-spacing: -0.02em; }
.price-unit { color: var(--color-text-light); font-size: 0.9rem; font-weight: 500; }
.savings-pill { padding: 4px 12px; border-radius: var(--radius-pill); font-size: 0.85rem; font-weight: 500; }

.btn-select {
	background: var(--color-primary);
	color: #fff;
	padding: 10px 24px;
	border-radius: var(--radius-pill);
	border: none;
	cursor: pointer;
	font-weight: 600;
	font-size: 1rem;
	font-family: var(--font-primary);
	display: flex;
	align-items: center;
	justify-content: center;
	gap: 8px;
	transition: background-color 0.2s ease;
	width: 100%;
	position: relative;
	overflow: hidden;
}

.btn-select:hover { background: var(--color-primary-hover); }

.btn-select::after {
	content: '';
	position: absolute;
	top: 0; left: -100%; 
	width: 50%; height: 100%;
	background: linear-gradient(to right, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.4) 50%, rgba(255, 255, 255, 0) 100%);
	transform: skewX(-20deg); 
	transition: left 0.6s ease-in-out;
}
.btn-select:hover::after { left: 150%; }

/*======================================
Responsive (Mobile & Tablette)
======================================*/
@media (max-width: 768px) {
	.top-bar-header {
		flex-direction: column;
		align-items: flex-start;
	}
	.offer-card {
		flex-direction: column;
		border-left-width: 4px !important;
	}
	.col-insurer, .col-action { flex: none; width: 100%; }
	.col-insurer { padding-bottom: 0; flex-direction: row; align-items: center; gap: var(--spacing); }
	.logo-box { margin-bottom: 0; width: 80px; height: 50px; }
	.col-features { padding: var(--spacing); }
	.vertical-divider { display: none; }
	.col-action { padding-top: 0; align-items: stretch; border-top: 1px solid var(--color-border); padding-top: var(--spacing); }
	.price-box, .savings-pill { align-self: center; }
}

