	</svg>
);

// --- Composant Pilule (Garanties) ---
function FeaturePill({ offer, featureName }) {
	const feature = getFeatureByName(offer, featureName);
	if (!feature || !feature.title) return null;

	const isTrue = feature.value === "true" || feature.value === true;
	const isFalse = feature.value === "false" || feature.value === false;

	if (!isTrue && !isFalse) return null;

