			)}

			{displayedOffers.map((offer, index) => (
				<OfferCard key={offer.id || index} offer={offer} />
			))}
		</div>
	);
}

function renderApp() {
	ReactDOM.render(<App />, document.getElementById("root"));
}

appsmith.onReady(() => renderApp());
appsmith.onModelChange(() => renderApp());
